import{useState,useEffect,useRef,useCallback}from"react";
const allQuestions = [{"id": 1, "s": "அறிமுகம்", "q": "இந்தியப் பொதுவுடைமை கட்சி எந்த ஆண்டு தாஷ்கண்டில் உருவாக்கப்பட்டது?", "o": ["1919 ஜனவரி", "1920 அக்டோபர்", "1921 மே", "1922 ஜூன்"], "a": 1, "e": "1920ஆம் ஆண்டு அக்டோபர் மாதத்தில் தாஷ்கண்டில் உருவாக்கப்பட்டது."}, {"id": 2, "s": "அறிமுகம்", "q": "இந்திய கம்யூனிஸ்ட் கட்சி இந்தியாவில் எந்த ஆண்டு, எங்கு முறைப்படி தொடங்கப்பட்டது?", "o": ["1924 கான்பூர்", "1925 பம்பாய்", "1927 கல்கத்தா", "1929 மீரட்"], "a": 1, "e": "இந்திய கம்யூனிஸ்ட் கட்சி 1925இல் பம்பாயில் முறைப்படி தொடங்கப்பட்டது."}, {"id": 3, "s": "அறிமுகம்", "q": "1921 ஜூன் 3இல் முதல் புரட்சிகர தேசியவாதக் குழுவினர் எங்கு வந்தனர்?", "o": ["லாகூர்", "கல்கத்தா", "பெஷாவர்", "பம்பாய்"], "a": 2, "e": "1921 ஜூன் 3இல் முதல் புரட்சிகர தேசியவாதக் குழுவினர் பெஷாவருக்கு வந்தனர்."}, {"id": 4, "s": "அறிமுகம்", "q": "1922-1927 ஆண்டுகளுக்கு இடையில் மொத்தம் எத்தனை சதி வழக்குகள் தொடுக்கப்பட்டன?", "o": ["மூன்று", "நான்கு", "ஐந்து", "ஆறு"], "a": 2, "e": "1922-1927ஆம் ஆண்டுகளுக்கு இடையில் ஐந்து சதி வழக்குகள் தொடுக்கப்பட்டன."}, {"id": 5, "s": "அறிமுகம்", "q": "முதலாவது சதி வழக்கு எது?", "o": ["கான்பூர் சதி வழக்கு", "பெஷாவர் சதி வழக்கு", "மீரட் சதி வழக்கு", "லாகூர் சதி வழக்கு"], "a": 1, "e": "முதலாவது பெஷாவர் சதி வழக்கு ஆகும்."}, {"id": 6, "s": "கான்பூர் சதி வழக்கு", "q": "கான்பூர் சதி வழக்கில் ஆரம்பத்தில் எத்தனை பேர் மீது குற்றம் சுமத்தப்பட்டது?", "o": ["8", "10", "13", "15"], "a": 2, "e": "கான்பூர் சதிவழக்கில் ஆரம்பத்தில் 13 பேர் மீது குற்றம் சுமத்தப்பட்டது."}, {"id": 7, "s": "கான்பூர் சதி வழக்கு", "q": "கான்பூர் சதிவழக்கில் இறுதியில் எத்தனை பேர் மீது குற்றப்பத்திரிகை தாக்கல் செய்யப்பட்டது?", "o": ["6", "7", "8", "9"], "a": 2, "e": "8 பேர் மீதே குற்றப்பத்திரிகை தாக்கல் செய்யப்பட்டது."}, {"id": 8, "s": "கான்பூர் சதி வழக்கு", "q": "கான்பூர் சதி வழக்கில் அரசுத் தரப்புச் சாட்சியாக மாறியவர் யார்?", "o": ["சவுகத் உஸ்மானி", "குலாம் ஹுசைன்", "நளினி குப்தா", "எஸ்.ஏ. டாங்கே"], "a": 1, "e": "குலாம் ஹுசைன் அரசுத் தரப்புச் சாட்சியாக மாறிவிட்டதால் அவர் விடுவிக்கப்பட்டார்."}, {"id": 9, "s": "கான்பூர் சதி வழக்கு", "q": "நீதிபதி H.E. ஹோம்ஸ் சௌரிசௌரா வழக்கில் எத்தனை விவசாயிகளுக்கு மரணதண்டனை விதித்தார்?", "o": ["72", "100", "172", "272"], "a": 2, "e": "சௌரிசௌரா வழக்கில் 172 விவசாயிகளுக்கு மரணதண்டனை விதித்தவர்."}, {"id": 10, "s": "கான்பூர் சதி வழக்கு", "q": "கான்பூர் சதி வழக்கில் குற்றவாளிகளுக்கு அளிக்கப்பட்ட கடுங்காவல் தண்டனை எத்தனை ஆண்டுகள்?", "o": ["2 ஆண்டுகள்", "4 ஆண்டுகள்", "6 ஆண்டுகள்", "8 ஆண்டுகள்"], "a": 1, "e": "முசாபர் அகமது, சவுகத் உஸ்மானி, நளினி குப்தா, எஸ். ஏ. டாங்கே ஆகியோர் நான்கு ஆண்டுகள் கடுங்காவல் தண்டனை அனுபவித்தனர்."}, {"id": 11, "s": "கான்பூர் சதி வழக்கு", "q": "எம். சிங்காரவேலர் எந்த காரணத்திற்காக பிணையில் விடுவிக்கப்பட்டார்?", "o": ["சிறு வயது", "மோசமான உடல்நிலை", "அரசுக்கு ஒத்துழைத்தமை", "வழக்கு திரும்பப் பெறப்பட்டது"], "a": 1, "e": "சிங்காரவேலர் மோசமான உடல்நிலை காரணமாகப் பிணையில் விடுவிக்கப்பட்டார்."}, {"id": 12, "s": "கான்பூர் சதி வழக்கு", "q": "எம். சிங்காரவேலர் எந்த ஆண்டு மே தினம் கொண்டாடினார்?", "o": ["1921", "1922", "1923", "1924"], "a": 2, "e": "1923ஆம் ஆண்டு மே மாதம் முதல் நாள் முதன்முறையாக நாட்டில் மே தினத்தைக் கொண்டாடினார்."}, {"id": 13, "s": "கான்பூர் சதி வழக்கு", "q": "எம். சிங்காரவேலர் எந்த ஆண்டு பிறந்தார்?", "o": ["1850", "1860", "1870", "1880"], "a": 1, "e": "எம். சிங்காரவேலர் 18 பிப்ரவரி 1860இல் மதராசில் பிறந்தார்."}, {"id": 14, "s": "கான்பூர் சதி வழக்கு", "q": "கான்பூர் சதி வழக்கு என்ன ஆண்டில் நடந்தது?", "o": ["1922", "1923", "1924", "1925"], "a": 2, "e": "1924ஆம் ஆண்டின் கான்பூர் சதிவழக்கு நடந்தது."}, {"id": 15, "s": "கான்பூர் சதி வழக்கு", "q": "எம்.என். ராய் எங்கு இருந்ததால் நேரில் வரவழைக்கப்படவில்லை?", "o": ["பாகிஸ்தான்", "பிரான்ஸ்", "ஜெர்மனி", "சோவியத் யூனியன்"], "a": 2, "e": "எம். என். ராய் ஜெர்மனியிலும் ஆர். எல். சர்மா பாண்டிச்சேரியிலும் இருந்ததால் நேரில் வரவழைக்காமல் குற்றப்பத்திரிகைகள் அனுப்பிவைக்கப்பட்டன."}, {"id": 16, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கு எந்த ஆண்டு தொடங்கியது?", "o": ["1927", "1928", "1929", "1930"], "a": 2, "e": "1929ஆம் ஆண்டின் மீரட் சதி வழக்கு நடந்தது."}, {"id": 17, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கில் மொத்தம் எத்தனை பேர் கைது செய்யப்பட்டனர்?", "o": ["20", "32", "45", "50"], "a": 1, "e": "கம்யூனிஸ்ட் கட்சியின் 32 முன்னோடிச் செயல்பாட்டாளர்களைக் கைது செய்தது."}, {"id": 18, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கில் விசாரணை எங்கு நடத்தப்பட்டது?", "o": ["பம்பாய்", "கல்கத்தா", "மீரட்", "லாகூர்"], "a": 2, "e": "விசாரணையை மீரட் நகரில் நடத்துவதென்று பிரிட்டானிய அரசு தீர்மானித்தது."}, {"id": 19, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கில் குற்றவாளிகள் சார்பில் வாதாடிய வழக்கறிஞர்கள் யார்?", "o": ["கே.எஃப். நாரிமன் மற்றும் எம்.சி. சக்லா", "காந்தி மற்றும் நேரு", "எம்.என். ராய் மற்றும் டாங்கே", "சிங்காரவேலர் மற்றும் முசாபர்"], "a": 0, "e": "கே.எஃப். நாரிமன், எம்.சி. சக்லா போன்ற புகழ்பெற்ற வழக்கறிஞர்கள் குற்றம் சாட்டப்பட்டவர்கள் சார்பில் நீதிமன்றத்தில் வாதாடினர்."}, {"id": 20, "s": "மீரட் சதி வழக்கு", "q": "மீரட் அமர்வு நீதிமன்றம் தீர்ப்பு வழங்கிய தேதி என்ன?", "o": ["1930 ஜனவரி 16", "1931 ஜனவரி 16", "1932 ஜனவரி 16", "1933 ஜனவரி 16"], "a": 3, "e": "1933 ஜனவரி 16இல் மீரட் அமர்வு நீதிமன்றம் கடுமையான தீர்ப்பை வழங்கியது."}, {"id": 21, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கில் தண்டிக்கப்பட்டவர்கள் எத்தனை பேர்?", "o": ["15", "20", "27", "32"], "a": 2, "e": "27 பேர் தண்டிக்கப்பட்டு வெவ்வேறு இடங்களுக்கு அனுப்பப்பட்டனர்."}, {"id": 22, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கு சர்வதேச அளவில் தெரிய வந்தது எதனால்?", "o": ["ஐரோப்பிய நாடுகளுக்கு கடிதம் எழுதினர்", "இங்கிலாந்து நாட்டினர் மூவர் குற்றம் சாட்டப்பட்டனர்", "ஐ.நா. தலையிட்டது", "அமெரிக்கா எதிர்ப்பு தெரிவித்தது"], "a": 1, "e": "இங்கிலாந்து நாட்டினர் மூவர் இந்த வழக்கில் குற்றம் சாட்டப்பட்டதைத் தொடர்ந்து சர்வதேச அளவிலும் தெரியவந்தது."}, {"id": 23, "s": "மீரட் சதி வழக்கு", "q": "மீரட் வழக்கில் ஆதரவாக குரல் கொடுத்த ஆளுமைகள் யாவர்?", "o": ["நெல்சன் மண்டேலா மற்றும் மார்ட்டின் லூதர் கிங்", "ரோமன் ரோலண்ட் மற்றும் ஆல்பர்ட் ஐன்ஸ்டீன்", "சார்லி சாப்ளின் மற்றும் பெர்ட்ரண்ட் ரசல்", "ஜார்ஜ் பர்னாட் ஷா மற்றும் ஹெலன் கெல்லர்"], "a": 1, "e": "ரோமன் ரோலண்ட், ஆல்பர்ட் ஐன்ஸ்டீன் போன்றவர்களும் குற்றம் சாட்டப்பட்டவர்களுக்கு ஆதரவாகக் குரல் கொடுத்தனர்."}, {"id": 24, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கில் தண்டனை எப்போது குறைக்கப்பட்டது?", "o": ["1933 ஜனவரி", "1933 மார்ச்", "1933 ஜூலை", "1933 டிசம்பர்"], "a": 2, "e": "ஜூலை 1933இல் தண்டனை வெகுவாகக் குறைக்கப்பட்டது."}, {"id": 25, "s": "மீரட் சதி வழக்கு", "q": "1928ஆம் ஆண்டு ஆங்கிலேய அரசு இயற்றிய இரண்டு கொடுஞ்சட்டங்கள் எவை?", "o": ["தொழிற்தகராறுகள் சட்டம் மற்றும் பொதுமக்கள் பாதுகாப்பு மசோதா", "கோலாகல சட்டம் மற்றும் பாதுகாப்பு சட்டம்", "தொழிற்சங்க சட்டம் மற்றும் வேலைநிறுத்த தடைச் சட்டம்", "ரவுலட் சட்டம் மற்றும் பிரிட்டிஷ் பாதுகாப்பு சட்டம்"], "a": 0, "e": "ஆங்கிலேய அரசு 1928ஆம் ஆண்டின் தொழிற்தகராறுகள் சட்டம், 1928ஆம் ஆண்டின் பொதுமக்கள் பாதுகாப்பு மசோதா ஆகிய இரு கொடுஞ்சட்டங்களை இயற்றியது."}, {"id": 26, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கில் கைது செய்யப்பட்டவர்களில் குறைந்தது எத்தனை பேர் காங்கிரஸ் உறுப்பினர்கள்?", "o": ["3 பேர்", "5 பேர்", "8 பேர்", "10 பேர்"], "a": 2, "e": "அவர்களில் குறைந்தபட்சம் 8 பேர் இந்திய தேசிய காங்கிரசைச் சேர்ந்தவர்கள்."}, {"id": 27, "s": "மீரட் சதி வழக்கு", "q": "மீரட் சதி வழக்கின் முக்கிய தாக்கம் என்ன?", "o": ["கம்யூனிஸ்ட் இயக்கம் அழிந்தது", "லட்சக்கணக்கான மக்கள் கம்யூனிசச் சித்தாந்தம் குறித்து அறிந்துகொண்டனர்", "தொழிற்சங்கங்கள் கலைக்கப்பட்டன", "இந்திய கம்யூனிஸ்ட் கட்சி தடை செய்யப்பட்டது"], "a": 1, "e": "அவை செய்தித்தாள்களில் பரவலாக வெளியாகி அதன்வழியாக லட்சக்கணக்கான மக்கள் கம்யூனிசச் சித்தாந்தம் குறித்தும் கம்யூனிஸ்டுகளின் செயல்பாடுகள் குறித்தும் அறிந்துகொண்டனர்."}, {"id": 28, "s": "பகத்சிங்", "q": "பகத்சிங் எந்த ஆண்டு எங்கு பிறந்தார்?", "o": ["1905 அலகாபாத்", "1907 செப்டம்பர் 28 ஜார்ன்வாலா", "1910 லாகூர்", "1912 அமிர்தசரஸ்"], "a": 1, "e": "பகத்சிங் லயல்பூர் மாவட்டம், ஜார்ன்வாலா என்ற இடத்தில் 1907 செப்டம்பர் 28இல் பிறந்தார்."}, {"id": 29, "s": "பகத்சிங்", "q": "பகத்சிங்கின் தந்தையின் பெயர் என்ன?", "o": ["கிஷன்சிங்", "அஜித்சிங்", "சுகதேவ்சிங்", "ஜெகத்சிங்"], "a": 0, "e": "கிஷன்சிங் (தகப்பனார்) என்பவர் பகத்சிங்கின் தந்தை."}, {"id": 30, "s": "பகத்சிங்", "q": "பகத்சிங்கின் தாயார் பெயர் என்ன?", "o": ["சாவித்ரி தேவி", "வித்யாவதி கவுர்", "கல்யாணி தேவி", "ராதா ரானி"], "a": 1, "e": "வித்யாவதி கவுர் என்பவர் பகத்சிங்கின் தாயார்."}, {"id": 31, "s": "பகத்சிங்", "q": "பகத்சிங் எந்த வயதில் ஜாலியன் வாலாபாக் படுகொலை கண்டார்?", "o": ["10ஆம் வயது", "12ஆம் வயது", "14ஆம் வயது", "16ஆம் வயது"], "a": 2, "e": "பகத்சிங்கின் 14ஆம் வயதில் ஜாலியன் வாலாபாக் படுகொலை நிகழ்ந்தது."}, {"id": 32, "s": "பகத்சிங்", "q": "ஹிந்துஸ்தான் ரிபப்ளிகன் அசோசியேஷனை யார் தோற்றுவித்தனர்?", "o": ["பகத்சிங் மற்றும் ஆசாத்", "சச்சின் சன்யால் மற்றும் ஜோகேஷ் சட்டர்ஜி", "சூரியா சென் மற்றும் கல்பனா தத்", "சுகதேவ் மற்றும் ராஜகுரு"], "a": 1, "e": "ஹிந்துஸ்தான் ரிபப்ளிகன் அசோசியேஷன் சச்சின் சன்யால், ஜோகேஷ் சட்டர்ஜி ஆகியோரால் தோற்றுவிக்கப்பட்டது."}, {"id": 33, "s": "பகத்சிங்", "q": "HSRA என்று பெயர் மாற்றப்பட்ட ஆண்டு எது?", "o": ["1926", "1927", "1928", "1929"], "a": 2, "e": "1928இல் ஹிந்துஸ்தான் சோசலிஸ்ட் ரிபப்ளிகன் அசோசியேஷன் என்று பெயர் மாற்றம் செய்யப்பட்டது."}, {"id": 34, "s": "பகத்சிங்", "q": "பகத்சிங் மத்திய சட்டமன்றத்தில் குண்டு வீசிய தேதி என்ன?", "o": ["1928 ஏப்ரல் 8", "1929 ஏப்ரல் 8", "1930 ஏப்ரல் 8", "1929 ஜூன் 8"], "a": 1, "e": "பகத்சிங் 1929 ஏப்ரல் 8இல் மத்திய சட்டமன்றத்தில் குண்டு வீசினார்."}, {"id": 35, "s": "பகத்சிங்", "q": "பகத்சிங் சட்டமன்றத்தில் குண்டு வீசியது யாரையாவது கொன்றதா?", "o": ["ஆம் பலர் இறந்தனர்", "ஆம் ஒருவர் இறந்தார்", "இல்லை யாரும் கொல்லப்படவில்லை", "ஒருவர் காயமடைந்தார் மட்டும்"], "a": 2, "e": "அந்தக் குண்டுகள் எவரையும் கொல்லவில்லை."}, {"id": 36, "s": "பகத்சிங்", "q": "இரண்டாவது லாகூர் சதி வழக்கு எதை மையமாகக் கொண்டது?", "o": ["குண்டு வீச்சு", "சாண்டர்ஸ் கொலை", "ரயில் குண்டு", "ஆயுதக் கிடங்கு தாக்குதல்"], "a": 1, "e": "சாண்டர்ஸ் கொலை தொடர்பான விசாரணைக்கு அவர்கள் ஆளாக்கப்பட்டனர் (இரண்டாவது லாகூர் சதி வழக்கு என்று அறியப்படுகிறது)."}, {"id": 37, "s": "பகத்சிங்", "q": "ஜதீந்திரநாத் தாஸ் எத்தனை நாட்கள் உண்ணாவிரதம் இருந்து மரணமடைந்தார்?", "o": ["30 நாட்கள்", "45 நாட்கள்", "64 நாட்கள்", "90 நாட்கள்"], "a": 2, "e": "உண்ணாவிரதம் மேற்கொண்ட ஜதீந்திரநாத் தாஸ் 64 நாட்களுக்குப் பின்னர் சிறையிலேயே மரணம் அடைந்தார்."}, {"id": 38, "s": "பகத்சிங்", "q": "பகத்சிங் ராஜகுரு சுகதேவ் ஆகியோருக்கு மரண தண்டனை விதிக்கப்பட்ட தேதி என்ன?", "o": ["1930 அக்டோபர் 7", "1931 மார்ச் 23", "1930 செப்டம்பர் 7", "1931 ஏப்ரல் 8"], "a": 0, "e": "பகத்சிங், ராஜகுரு, சுகதேவ் ஆகியோருக்கு 1930 அக்டோபர் 7 அன்று மரண தண்டனை விதிக்கப்பட்டது."}, {"id": 39, "s": "பகத்சிங்", "q": "பகத்சிங் ராஜகுரு சுகதேவ் தூக்கிலிடப்பட்ட தேதி என்ன?", "o": ["1930 மார்ச் 23", "1931 மார்ச் 23", "1931 ஏப்ரல் 6", "1932 ஜனவரி 1"], "a": 1, "e": "லாகூர் சிறைச்சாலையில் 1931 மார்ச் 23 அன்று அதிகாலையில் தூக்கிலிடப்பட்டனர்."}, {"id": 40, "s": "பகத்சிங்", "q": "பகத்சிங் பஞ்சாப் மாநில ஆளுநருக்கு கடிதத்தில் என்ன கோரினார்?", "o": ["விடுதலை அளிக்கவும்", "தூக்கிலிடுவதற்குப் பதிலாகச் சுட்டுக் கொல்லும்படி", "வழக்கை திரும்பப் பெறும்படி", "குடும்பத்தினரை சந்திக்க அனுமதிக்கும்படி"], "a": 1, "e": "நாங்கள் போர் தொடுத்ததால் போர்க் கைதிகளானோம். எங்களைத் தூக்கிலிடுவதற்குப் பதிலாகச் சுட்டுக் கொல்லுங்கள் என்று கோரப்பட்டிருந்தது."}, {"id": 41, "s": "பகத்சிங்", "q": "HSRA-வின் குறிக்கோள் என்ன?", "o": ["காந்திய அகிம்சை பாதை", "முதலாளித்துவ ஏகாதிபத்திய அரசை தூக்கி எறிந்து சோசலிசச் சமூகம் நிலைநாட்டுவது", "பிரிட்டிஷ் ஆட்சியுடன் பேச்சுவார்த்தை", "கல்வி மூலம் சுதந்திரம்"], "a": 1, "e": "முதலாளித்துவ ஏகாதிபத்திய அரசைத் தூக்கி எறிந்து புரட்சி ஒன்றின் மூலமாக ஒரு சோசலிசச் சமூகத்தை நிலைநாட்டுவதே அதன் குறிக்கோளாகும்."}, {"id": 42, "s": "பகத்சிங்", "q": "சாண்டர்ஸின் கொலைக்கு உண்மையான இலக்கு யார்?", "o": ["ஜேம்ஸ் ஏ. ஸ்காட்", "இர்வின் பிரபு", "ரவுலட்", "டயர்"], "a": 0, "e": "லஜபதி ராய் மீது தாக்குதல் நடத்தியதற்கும் ராயின் மரணத்திற்கும் பொறுப்பான ஜேம்ஸ் ஏ. ஸ்காட்டுக்குப் பதில் தவறுதலாக சாண்டர்ஸ் பலியானார்."}, {"id": 43, "s": "பகத்சிங்", "q": "பகத்சிங் புரட்சி என்பதை எவ்வாறு வரையறுத்தார்?", "o": ["வன்முறை மட்டுமே", "குண்டு எறிதல் மட்டுமே", "மனிதகுலத்தின் பிரிக்க முடியாத உரிமை", "ஆங்கிலேயர்களை துரத்துவது"], "a": 2, "e": "புரட்சி என்பது வெறும் குண்டு எறிதலோ சுடுவதோ அல்ல. புரட்சி என்பது மனிதகுலத்தின் பிரிக்க முடியாத உரிமை ஆகும் என்று கூறினார்."}, {"id": 44, "s": "பகத்சிங்", "q": "HSRA-வின் முழு விரிவு என்ன?", "o": ["Hindu Socialist Republic Association", "Hindustan Socialist Republican Association", "Hindustan Social Reform Assembly", "Hindustan Students Revolutionary Assembly"], "a": 1, "e": "HSRA என்பது Hindustan Socialist Republican Association - ஹிந்துஸ்தான் சோசலிஸ்ட் ரிபப்ளிகன் அசோசியேஷன்."}, {"id": 45, "s": "பகத்சிங்", "q": "HSRA-வில் பகத்சிங்கோடு இணைந்து செயல்பட்டவர்கள் யாவர்?", "o": ["ஆசாத் ராஜகுரு சுகதேவ்", "சூரியா சென் கல்பனா தத்", "எம்.என். ராய் டாங்கே", "சிங்காரவேலர் முசாபர்"], "a": 0, "e": "சந்திரசேகர ஆசாத், சிவராம் ராஜகுரு, சுகதேவ் தாபர் ஆகியோருடன் ஹிந்துஸ்தான் சோசலிஸ்ட் ரிபப்ளிகன் அசோசியேஷனின் தலைவர்களில் ஒருவராக பகத்சிங் விளங்கினார்."}, {"id": 46, "s": "கல்பனா தத்", "q": "கல்பனா தத் எந்த ஆண்டுகளில் வாழ்ந்தார்?", "o": ["1910-1990", "1913-1995", "1915-2000", "1920-1985"], "a": 1, "e": "கல்பனா தத் 1913 - 1995 ஆண்டுகளில் வாழ்ந்தார்."}, {"id": 47, "s": "கல்பனா தத்", "q": "கல்பனா தத் யாரை திருமணம் செய்துகொண்டார்?", "o": ["சூரியா சென்", "பி.சி. ஜோஷி", "பகத்சிங்", "முசாபர் அகமது"], "a": 1, "e": "கம்யூனிஸ்ட் தலைவர் பி.சி. ஜோஷியைத் திருமணம் செய்து கொண்ட பின்னர் கல்பனா ஜோஷி என்று அறியப்பட்டவர்."}, {"id": 48, "s": "கல்பனா தத்", "q": "கல்பனா தத் எழுதிய நூல் எது?", "o": ["My Life in Revolution", "Chittagong Armoury Raiders Reminiscences", "The Indian Struggle", "Freedom Daughter"], "a": 1, "e": "Chittagong Armoury Raiders Reminiscences என்னும் நூல் கல்பனா தத்தால் எழுதப்பட்டது."}, {"id": 49, "s": "கல்பனா தத்", "q": "கல்பனா தத் மீது சுமத்தப்பட்ட குற்றச்சாட்டு என்ன?", "o": ["கள்ளக் கடத்தல்", "பேரரசருக்கு எதிரான போரை நடத்தியது", "ஆயுத கடத்தல்", "உளவுப் பணி"], "a": 1, "e": "பேரரசருக்கு எதிரான போரை நடத்தியது என்று குற்றம் சாட்டப்பட்டார்."}, {"id": 50, "s": "கல்பனா தத்", "q": "சிட்டகாங் ஆயுதப் படைத் தாக்குதல் நடைபெற்ற தேதி என்ன?", "o": ["1929 ஏப்ரல் 18", "1930 ஏப்ரல் 18", "1931 ஏப்ரல் 18", "1932 ஏப்ரல் 18"], "a": 1, "e": "1930 ஏப்ரல் 18 அன்று இரவில் சிட்டகாங் படைத்தளம் தாக்கித் தகர்க்கப்பட்டது."}, {"id": 51, "s": "கல்பனா தத்", "q": "சூரியா சென் கைது செய்யப்பட்ட ஆண்டு எது?", "o": ["1931", "1932", "1933", "1934"], "a": 2, "e": "சூரியா சென்னைக் கைது செய்ய மூன்று ஆண்டுகள் பிடித்தன. பிப்ரவரி 1933இல் அவர் கைதானார்."}, {"id": 52, "s": "கல்பனா தத்", "q": "சூரியா சென்னுக்கு தூக்குத்தண்டனை நிறைவேற்றப்பட்ட தேதி என்ன?", "o": ["1933 டிசம்பர் 12", "1934 ஜனவரி 12", "1933 மார்ச் 23", "1934 மார்ச் 23"], "a": 1, "e": "பதினொரு மாதங்கள் கழித்து 1934 ஜனவரி 12இல் அவருக்குத் தூக்குத்தண்டனை நிறைவேற்றப்பட்டது."}, {"id": 53, "s": "கல்பனா தத்", "q": "சூரியா சென் எந்தத் தொழிலில் இருந்தார்?", "o": ["மருத்துவர்", "வழக்கறிஞர்", "பள்ளி ஆசிரியர்", "பொறியாளர்"], "a": 2, "e": "வங்காளத்தில் பள்ளிக்கூடம் ஒன்றில் ஆசிரியராகப் பணிபுரிந்த சூரியா சென்னின் தலைமையில் செயல்பட்ட குழு முக்கியமானதாகும்."}, {"id": 54, "s": "கல்பனா தத்", "q": "சிட்டகாங் தாக்குதல் தொடர்ந்து எத்தனை ஆண்டுகள் நீடித்தது?", "o": ["1 ஆண்டு", "2 ஆண்டுகள்", "3 ஆண்டுகள்", "5 ஆண்டுகள்"], "a": 2, "e": "இந்தத் தாக்குதல்களும் எதிர்ப்பும் அடுத்த மூன்று ஆண்டுகளுக்குத் தொடர்ந்தன."}, {"id": 55, "s": "கல்பனா தத்", "q": "கல்பனா தத்துக்கு அளிக்கப்பட்ட தண்டனை என்ன?", "o": ["20 ஆண்டு சிறைத்தண்டனை", "வாழ்நாள் நாடுகடத்தல்", "மரண தண்டனை", "5 ஆண்டு சிறை"], "a": 1, "e": "தண்டனையாக கல்பனா தத் வாழ்நாள் முழுதும் நாடுகடத்தப்பட்டார்."}, {"id": 56, "s": "கல்பனா தத்", "q": "சிட்டகாங் தாக்குதலில் புரட்சியாளர்கள் முழங்கிய கோஷங்கள் எவை?", "o": ["ஜய் ஹிந்த் வந்தே மாதரம்", "வந்தே மாதரம் புரட்சி ஓங்குக", "அல்லா ஹோ அக்பர் வந்தே மாதரம்", "இன்குலாப் ஜிந்தாபாத் மட்டும்"], "a": 1, "e": "புரட்சியாளர்கள் தேசியக்கொடியை ஏற்றி வந்தே மாதரம், புரட்சி ஓங்குக போன்ற கோஷங்களை முழங்கினர்."}, {"id": 57, "s": "கல்பனா தத்", "q": "சூரியா சென்னின் குழு எந்த இராணுவத்தைப் போல் பெயர் சூட்டிக்கொண்டது?", "o": ["அமெரிக்க குடியரசு படை", "ஐரிஷ் குடியரசுப் படை", "பிரெஞ்சு குடியரசு படை", "ரஷ்ய சோவியத் படை"], "a": 1, "e": "சூரியா சென்னின் இந்தியக் குடியரசு இராணுவம் ஐரிஷ் குடியரசுப் படைக்குப் பின் அதுபோன்று பெயர் சூட்டிக்கொண்டது."}, {"id": 58, "s": "கல்பனா தத்", "q": "சிட்டகாங் தாக்குதலுக்குப் பிறகு புரட்சியாளர்கள் எங்கிருந்து செயல்பட்டனர்?", "o": ["நகரங்களிலிருந்து", "கிராமங்களிலிருந்து", "மலைப் பகுதிகளிலிருந்து", "வெளிநாட்டிலிருந்து"], "a": 1, "e": "பெரிதும் அவர்கள் கிராமங்களிலிருந்து செயல்பட்டனர். கிராமத்தினர் அவர்களுக்கு உணவும் உறைவிடமும் அளித்தனர்."}, {"id": 59, "s": "கராச்சி அமர்வு", "q": "இந்திய தேசிய காங்கிரசின் கராச்சி அமர்வு எந்த ஆண்டு நடந்தது?", "o": ["1929", "1930", "1931", "1932"], "a": 2, "e": "மார்ச் 1931இல் நடந்த கராச்சி அமர்வு."}, {"id": 60, "s": "கராச்சி அமர்வு", "q": "கராச்சி அமர்வுக்கு தலைமை தாங்கியவர் யார்?", "o": ["ஜவகர்லால் நேரு", "மகாத்மா காந்தி", "சர்தார் வல்லபாய் படேல்", "சுபாஷ் சந்திர போஸ்"], "a": 2, "e": "மார்ச் 1931இல் நடந்த கராச்சி அமர்வு சர்தார் வல்லபாய் படேல் தலைமையில் நடந்தது."}, {"id": 61, "s": "கராச்சி அமர்வு", "q": "கராச்சி அமர்வில் நிறைவேற்றப்பட்ட முக்கிய தீர்மானம் என்ன?", "o": ["முழு சுதந்திர தீர்மானம்", "அடிப்படை உரிமைகள் மற்றும் கடமைகள் தீர்மானம்", "சட்டமறுப்பு இயக்க தீர்மானம்", "கில்லாஃபத் ஒத்துழைப்பு தீர்மானம்"], "a": 1, "e": "அடிப்படை உரிமைகள் மற்றும் கடமைகளில் ஒரு தீர்மானத்தை நிறைவேற்றியது."}, {"id": 62, "s": "கராச்சி அமர்வு", "q": "அடிப்படை உரிமைகள் இந்திய அரசமைப்பின் எந்த பகுதியில் இடம்பெற்றுள்ளன?", "o": ["பகுதி I", "பகுதி II", "பகுதி III", "பகுதி IV"], "a": 2, "e": "அடிப்படை உரிமைகள் உண்மையில் இந்திய அரசமைப்பின் பகுதி IIIல் இடம்பெற்றுள்ளன."}, {"id": 63, "s": "கராச்சி அமர்வு", "q": "கராச்சி அமர்வு எதை நிரூபித்தது?", "o": ["அரசியல் சுதந்திரம் மட்டுமே வேண்டும்", "அரசியல் சுதந்திரம் மற்றும் பொருளாதாரச் சுதந்திரம் பிரிக்க முடியாதவை", "பொருளாதார சுதந்திரம் மட்டுமே வேண்டும்", "சமூக சமத்துவம் அவசியமில்லை"], "a": 1, "e": "அரசியல் சுதந்திரம் மற்றும் பொருளாதாரச் சுதந்திரம் என்பது பிரித்துப் பார்க்கமுடியாத ஒன்றென்று உறுதிசெய்தன."}, {"id": 64, "s": "கராச்சி அமர்வு", "q": "வழிகாட்டு நெறிமுறைகள் அரசமைப்பின் எந்த பகுதியில் இடம்பெற்றுள்ளன?", "o": ["பகுதி I", "பகுதி II", "பகுதி III", "பகுதி IV"], "a": 3, "e": "சில அடிப்படை உரிமைகள் பகுதி IVல் நாட்டின் அரசு வழிகாட்டு நெறிமுறைகளில் இடம்பெற்றுள்ளன."}, {"id": 65, "s": "கராச்சி அமர்வு", "q": "1930களில் விவசாயிகள் எந்த அமைப்பில் சேர்ந்தனர்?", "o": ["தொழிற்சங்கம்", "கிசான் சபா", "இந்திய தேசிய காங்கிரஸ்", "கம்யூனிஸ்ட் கட்சி"], "a": 1, "e": "விவசாயிகள் கிசான் சபா எனப்படும் விவசாயிகள் சங்கத்தில் தங்களை இணைத்துக்கொண்டனர்."}, {"id": 66, "s": "கராச்சி அமர்வு", "q": "கராச்சி அமர்வின் கொள்கை அறிவிப்பில் யாருடைய கொள்கைகள் இடம்பெற்றன?", "o": ["நேரு மட்டும்", "காந்தி மட்டும்", "காந்தியின் கொள்கைகளும் நேருவின் சோசலிச பார்வைகளும்", "போஸின் தேசியவாதமும்"], "a": 2, "e": "சுதந்திர இந்தியாவில் காங்கிரஸ் வழங்க உறுதியளித்துள்ள உரிமைகள் பட்டியலில் காந்தியடிகளின் கொள்கைகளும் நேருவின் சோசலிச பார்வைகளும் இடம் பெற்றன."}, {"id": 67, "s": "பெருமந்தம்", "q": "உலகப் பெருமந்த நிலை எந்த ஆண்டு தொடங்கியது?", "o": ["1927", "1928", "1929", "1930"], "a": 2, "e": "உலகப் பெருமந்த நிலை 1929இல் இருந்து ஒரு பத்தாண்டாக நீடித்தது."}, {"id": 68, "s": "பெருமந்தம்", "q": "உலகப் பெருமந்தம் எந்த நாட்டில் தொடங்கியது?", "o": ["பிரிட்டன்", "ஜெர்மனி", "வட அமெரிக்கா", "ஜப்பான்"], "a": 2, "e": "வட அமெரிக்காவில் தொடங்கிய பொருளாதாரப் பெருமந்தம்."}, {"id": 69, "s": "பெருமந்தம்", "q": "உலகப் பெருமந்தம் எத்தனை ஆண்டுகள் நீடித்தது?", "o": ["5 ஆண்டுகள்", "7 ஆண்டுகள்", "10 ஆண்டுகள்", "15 ஆண்டுகள்"], "a": 2, "e": "உலகப் பெருமந்த நிலை 1929இல் இருந்து 1939 வரை ஒரு பத்தாண்டாக நீடித்தது."}, {"id": 70, "s": "பெருமந்தம்", "q": "1929-30இல் இந்தியாவின் ஏற்றுமதி மதிப்பு எவ்வளவு?", "o": ["ரூ.131 கோடி", "ரூ.211 கோடி", "ரூ.311 கோடி", "ரூ.411 கோடி"], "a": 2, "e": "1929-1930இல் ரூ.311 கோடியாயிருந்த இந்திய ஏற்றுமதியின் மதிப்பு 1932-1933இல் ரூ.132 கோடியாகச் சரிந்தது."}, {"id": 71, "s": "பெருமந்தம்", "q": "1932-33இல் இந்தியாவின் ஏற்றுமதி மதிப்பு எவ்வளவாக குறைந்தது?", "o": ["ரூ.100 கோடி", "ரூ.132 கோடி", "ரூ.165 கோடி", "ரூ.200 கோடி"], "a": 1, "e": "1932-1933இல் ரூ.132 கோடியாகச் சரிந்தது."}, {"id": 72, "s": "பெருமந்தம்", "q": "கிசான் சபாக்கள் எதற்காக போராடின?", "o": ["வேலை உரிமை", "குத்தகை குறைப்பு கடன் நிவாரணம் ஜமீன்தாரி முறை அகற்றல்", "வாக்குரிமை", "கல்வி உரிமை"], "a": 1, "e": "கிசான் சபாக்கள் குத்தகை குறைப்புகள், கடன் பிடியிலிருந்து நிவாரணம், ஜமீன்தாரி முறை அகற்றப்படுதல் ஆகியவற்றிற்காகப் போராடியது."}, {"id": 73, "s": "பெருமந்தம்", "q": "பெருமந்தத்தின் போது இந்தியாவில் எந்தெந்த ஏற்றுமதி பொருட்களின் விலை சரிந்தன?", "o": ["தேக்கட்டை மற்றும் இரும்பு", "சணல் மற்றும் கச்சாப் பருத்தி", "தங்கம் மற்றும் வைரம்", "தேயிலை மற்றும் காபி"], "a": 1, "e": "வேளாண் துறையில், சணல் மற்றும் கச்சாப் பருத்தி போன்ற ஏற்றுமதி விவசாயப் பொருட்களின் விலைகள் சரிந்தன."}, {"id": 74, "s": "பெருமந்தம்", "q": "1929-30களில் இந்தியாவால் வெளியில் இருந்து நுகர்வு செய்யப்பட்ட பருத்திப் பொருட்கள் எத்தனை சதவீதம்?", "o": ["22 சதவீதம்", "33 சதவீதம்", "44 சதவீதம்", "55 சதவீதம்"], "a": 2, "e": "1929-30களில் இந்தியாவால் 44 சதவீதம் வெளியில் இருந்து நுகர்வு செய்யப்பட்ட பருத்திப் பொருட்கள் 1933-34இல் 20.5 சதவிகிதமாகக் குறைந்துவிட்டது."}, {"id": 75, "s": "தொழில்துறை வளர்ச்சி", "q": "இந்தியாவில் முதல் பருத்தி ஆலை யாரால் தொடங்கப்பட்டது?", "o": ["ஜே.என். டாடா", "கவஸ்ஜீ நானாபாய் தவர்", "துவாரகநாத் தாகூர்", "ரவீந்திரநாத் தாகூர்"], "a": 1, "e": "1854இல் பம்பாயில் கவஸ்ஜீ நானாபாய் தவர் (1815-73) என்ற பார்சி இனத்தைச் சேர்ந்த இந்தியரே பருத்தி ஆலையை முதன்முதலில் தொடங்கினார்."}, {"id": 76, "s": "தொழில்துறை வளர்ச்சி", "q": "பாம்பே ஸ்பின்னிங் அண்ட் வீவிங் கம்பெனி எந்த ஆண்டு தொடங்கப்பட்டது?", "o": ["1850", "1852", "1854", "1856"], "a": 2, "e": "1854இல் பம்பாயில் பாம்பே ஸ்பின்னிங் அண்ட் வீவிங் கம்பெனி தொடங்கப்பட்டது."}, {"id": 77, "s": "தொழில்துறை வளர்ச்சி", "q": "இந்தியாவின் முதல் பயணிகள் ரயில் எந்த ஆண்டு இயங்கியது?", "o": ["1851", "1852", "1853", "1854"], "a": 2, "e": "முதல் பயணிகள் ரயில் 1853இல் பம்பாய்க்கும் தானேவுக்கும் இடையே இயங்கியது."}, {"id": 78, "s": "தொழில்துறை வளர்ச்சி", "q": "இந்தியாவின் முதல் ரயில் எந்த நிலையத்திலிருந்து புறப்பட்டது?", "o": ["வி.டி. நிலையம்", "போரி பந்தர் இரயில் நிலையம்", "சர்ச் கேட் நிலையம்", "அண்டேரி நிலையம்"], "a": 1, "e": "போரி பந்தர் இரயில் நிலையத்திலிருந்து புறப்பட்டு 34 கி.மீ. தொலைவிலுள்ள தானே சென்றடைந்தது."}, {"id": 79, "s": "தொழில்துறை வளர்ச்சி", "q": "முதல் ரயில் பயணம் நடந்த தேதி மற்றும் நேரம் என்ன?", "o": ["1853 ஏப்ரல் 16 3:35 பிற்பகல்", "1853 மே 16 3:35 முற்பகல்", "1853 ஜூன் 16 5:00 பிற்பகல்", "1853 ஜூலை 16 3:35 பிற்பகல்"], "a": 0, "e": "1853 ஏப்ரல் 16, 3:35 பிற்பகல் அன்று இந்தியாவின் முதல் இரயில் பயணம் நடந்தது."}, {"id": 80, "s": "தொழில்துறை வளர்ச்சி", "q": "முதல் சணல் உற்பத்தி ஆலை எங்கு எந்த ஆண்டு நிறுவப்பட்டது?", "o": ["1850 பம்பாய்", "1855 கல்கத்தா", "1860 மதராஸ்", "1865 லாகூர்"], "a": 1, "e": "முதல் சணல் உற்பத்தி ஆலை கல்கத்தாவில் 1855இல் நிறுவப்பட்டது."}, {"id": 81, "s": "தொழில்துறை வளர்ச்சி", "q": "1914ஆம் ஆண்டில் கல்கத்தா மாகாணத்தில் எத்தனை சணல் ஆலைகள் இருந்தன?", "o": ["25", "40", "64", "100"], "a": 2, "e": "1914ஆம் ஆண்டில் கல்கத்தா மாகாணத்தில் மட்டும் 64 ஆலைகள் இருந்தன."}, {"id": 82, "s": "தொழில்துறை வளர்ச்சி", "q": "TISCO எந்த ஆண்டு எங்கு நிறுவப்பட்டது?", "o": ["1905 பம்பாய்", "1907 சாகி நகர் பீகார்", "1910 கல்கத்தா", "1912 நாக்பூர்"], "a": 1, "e": "1907இல் பீகாரிலுள்ள சாகி நகரில் டாடா குழுமத்தால் டாடா இரும்பு மற்றும் எஃகு நிறுவனம் (TISCO) அமைக்கப்பட்டது."}, {"id": 83, "s": "தொழில்துறை வளர்ச்சி", "q": "ஜே.என். டாடாவை இந்திய நவீனத் தொழிலகங்களின் தந்தை என அழைப்பது ஏன்?", "o": ["முதல் தொழில் அமைத்தார்", "இந்தியாவின் முதல் வெற்றிகரமான தொழிலதிபர்", "அதிக செல்வம் சம்பாதித்தார்", "பல நாடுகளில் தொழில் நடத்தினார்"], "a": 1, "e": "இந்தியாவின் முதல் வெற்றிகரமான தொழிலதிபர் இவர் என்பதால், இந்திய நவீனத் தொழிலகங்களின் தந்தை என அழைக்கப்படுகிறார்."}, {"id": 84, "s": "தொழில்துறை வளர்ச்சி", "q": "ஜே.என். டாடா எந்த ஆண்டுகளில் வாழ்ந்தார்?", "o": ["1820-1885", "1839-1904", "1850-1920", "1860-1930"], "a": 1, "e": "ஜாம்ஷெட்ஜி நுசர்வஞ்சி டாடா (1839-1904) என்பவர் ஜே.என். டாடா."}, {"id": 85, "s": "தொழில்துறை வளர்ச்சி", "q": "டாடா குழுமம் எந்த ஆண்டு நிறுவப்பட்டது?", "o": ["1858", "1865", "1868", "1875"], "a": 2, "e": "1868இல் நிறுவப்பட்ட அவருடைய வர்த்தக நிறுவனம் டாடா குழுமம் என்றானது."}, {"id": 86, "s": "தொழில்துறை வளர்ச்சி", "q": "டாடா நீர்மின்சக்தி நிறுவனம் எந்த ஆண்டு உதயமானது?", "o": ["1907", "1910", "1912", "1915"], "a": 1, "e": "1910இல் மிகப்பெருமளவில் டாடா நீர்மின்சக்தி நிறுவனம் உதயமானது."}, {"id": 87, "s": "தொழில்துறை வளர்ச்சி", "q": "டாடா குழுமம் எங்கு இந்திய அறிவியல் கழகம் நிறுவியுள்ளது?", "o": ["பம்பாய்", "கல்கத்தா", "பெங்களூரு", "மதராஸ்"], "a": 2, "e": "இந்திய அறிவியல் கழகம் ஒன்றை பெங்களூரில் டாடா குழுமம் நிறுவியுள்ளது."}, {"id": 88, "s": "தொழில்துறை வளர்ச்சி", "q": "TISCO-ஐ யார் நிறுவினார்?", "o": ["ஜே.என். டாடா", "தோரப்ஜி டாடா", "ரத்தன்ஜி டாடா", "நெல்சன் டாடா"], "a": 1, "e": "தோரப்ஜி டாடா அவரது தந்தையின் நீண்ட கால கனவான இரும்பு மற்றும் எஃகு நிறுவனத்தை 1907ஆம் ஆண்டில் நிறுவினார்."}, {"id": 89, "s": "தொழில்துறை வளர்ச்சி", "q": "பெங்கால் நிலக்கரி நிறுவனம் யாரால் எந்த ஆண்டு நிறுவப்பட்டது?", "o": ["1840 ஜே.என். டாடா", "1843 துவாரகநாத் தாகூர்", "1850 ரவீந்திரநாத் தாகூர்", "1855 கவஸ்ஜீ தவர்"], "a": 1, "e": "1843இல் ரவீந்திரநாத் தாகூரின் தாத்தா துவாரகநாத் தாகூர் (1794-1847) என்பவரால் பெங்கால் நிலக்கரி நிறுவனம் நிறுவப்பட்டது."}, {"id": 90, "s": "தொழில்துறை வளர்ச்சி", "q": "லக்னோவில் முதல் காகித ஆலை எந்த ஆண்டு அமைக்கப்பட்டது?", "o": ["1870", "1882", "1890", "1900"], "a": 1, "e": "1882ஆம் ஆண்டில் லக்னோவில் முதல் காகித ஆலை கூப்பர் பேப்பர் மில் என்ற பெயரில் அமைக்கப்பட்டது."}, {"id": 91, "s": "தொழில்துறை வளர்ச்சி", "q": "சிமெண்ட் உற்பத்தி மதராஸ் நகரில் எந்த ஆண்டு தொடங்கியது?", "o": ["1895", "1900", "1904", "1910"], "a": 2, "e": "1904இல் மதராஸ் நகரில் தென்னிந்திய தொழிற்சாலை நிறுவனம் சிமெண்ட் உற்பத்தியைத் தொடங்கியது."}, {"id": 92, "s": "தொழில்துறை வளர்ச்சி", "q": "முதல் தோல் பதனிடும் தொழிற்சாலை (அரசு) எந்த ஆண்டு எங்கு அமைக்கப்பட்டது?", "o": ["1855 கல்கத்தா", "1860 கான்பூர்", "1865 மதராஸ்", "1870 பம்பாய்"], "a": 1, "e": "1860இல் கான்பூரில் அரசால் ஒரு தோல் பதனிடும் தொழிற்சாலை அமைக்கப்பட்டது."}, {"id": 93, "s": "தொழில்துறை வளர்ச்சி", "q": "இந்தியருக்குச் சொந்தமான முதல் தேசிய தோல் பதனிடும் தொழிற்சாலை எந்த ஆண்டு எங்கு அமைக்கப்பட்டது?", "o": ["1900 மதராஸ்", "1903 பம்பாய்", "1905 கல்கத்தா", "1908 கான்பூர்"], "a": 2, "e": "1905இல் முதன் முதலாக இந்தியருக்குச் சொந்தமான தேசிய தோல் பதனிடும் தொழிற்சாலை ஒன்று கல்கத்தாவில் அமைக்கப்பட்டது."}, {"id": 94, "s": "தொழில்துறை வளர்ச்சி", "q": "சிந்தியா நீராவிக் கப்பல் கம்பெனி எந்த ஆண்டு தொடங்கப்பட்டது?", "o": ["1915", "1917", "1919", "1921"], "a": 2, "e": "சிந்தியா நீராவிக் கப்பல் கம்பெனி லிமிடெட் (1919) ஏனையவற்றிற்கு முன்னோடியாக இருந்தது."}, {"id": 95, "s": "தொழில்துறை வளர்ச்சி", "q": "1914ஆம் ஆண்டு வாக்கில் பம்பாய் மாகாணத்தில் எத்தனை பருத்தி ஆலைகள் இருந்தன?", "o": ["75", "100", "129", "150"], "a": 2, "e": "1914ஆம் ஆண்டு வாக்கில், பம்பாய் மாகாணத்திற்குள் 129 நூற்பு, நெசவு மற்றும் பிற பருத்தி ஆலைகள் இருந்தன."}, {"id": 96, "s": "தொழில்துறை வளர்ச்சி", "q": "1875-76 முதல் 1913-14 வரை இந்தியாவில் பருத்தி ஜவுளி ஆலைகள் எத்தனையிலிருந்து எத்தனை ஆனது?", "o": ["25 to 150", "47 to 271", "100 to 400", "30 to 200"], "a": 1, "e": "1875-76க்கும் 1913-14க்கும் இடைப்பட்ட காலத்தில் இந்தியாவில் பருத்தி ஜவுளி ஆலைகள் எண்ணிக்கை 47 லிருந்து 271 ஆக அதிகரித்தது."}, {"id": 97, "s": "தொழில்துறை வளர்ச்சி", "q": "கோயம்புத்தூரில் ஸ்டேன்ஸ் மில் எந்த ஆண்டு நிறுவப்பட்டது?", "o": ["1880", "1886", "1896", "1906"], "a": 2, "e": "கோயம்புத்தூரில், 1896இல் ஸ்டேன்ஸ் மில் (கோயம்புத்தூர் நூற்பு மற்றும் நெசவு ஆலை) நிறுவப்பட்டது."}, {"id": 98, "s": "தொழில்துறை வளர்ச்சி", "q": "மதுக்கரை சிமெண்ட் தொழிற்சாலை எந்த ஆண்டு தொடங்கப்பட்டது?", "o": ["1928", "1930", "1932", "1934"], "a": 2, "e": "1932இல் கோயம்புத்தூர் மாவட்டத்தில் மதுக்கரை என்ற இடத்தில் சிமெண்ட் தொழிற்சாலை தொடங்கப்பட்டது."}, {"id": 99, "s": "தொழில்துறை வளர்ச்சி", "q": "1931-1936க்கு இடையில் சென்னை மாகாணத்தில் சர்க்கரை ஆலைகளின் எண்ணிக்கை எவ்வாறு மாறியது?", "o": ["5 to 20", "2 to 11", "10 to 50", "1 to 8"], "a": 1, "e": "1931-1936க்கு இடையில் சர்க்கரை ஆலைகளின் எண்ணிக்கை இரண்டிலிருந்து பதினொன்றாய் உயர்ந்தது."}, {"id": 100, "s": "தொழில்துறை வளர்ச்சி", "q": "TISCO-யில் 1912-13 மற்றும் 1917-18 இடையே உற்பத்தி எவ்வாறு மாறியது?", "o": ["31000 to 181000 ton", "50000 to 250000 ton", "10000 to 80000 ton", "25000 to 150000 ton"], "a": 0, "e": "TISCO உற்பத்தி 1912-13இல் 31,000 டன்னிலிருந்து 1917-18இல் 1,81,000 டன்னாக அதிகரித்துள்ளது."}];

const notesData=[
  {title:"அறிமுகம்",color:"#FF6B35",sections:[
    {h:"இந்திய கம்யூனிஸ்ட் கட்சியின் தோற்றம்",body:"இந்தியப் பொதுவுடைமை (கம்யூனிஸ்ட்) கட்சியானது 1920ஆம் ஆண்டு அக்டோபர் மாதத்தில் உஸ்பெகிஸ்தானிலுள்ள தாஷ்கண்டிலும் பின்னர் சோவியத் யூனியனிலும் உருவாக்கப்பட்டது.",
     tbl:{hs:["நிறுவனர்","பங்கு"],rows:[["எம்.என். ராய்","முக்கிய நிறுவனர்"],["அபானி முகர்ஜி","இணை நிறுவனர்"],["எம்.பி.டி. ஆச்சார்யா","இணை நிறுவனர்"],["முகமது அலி","இணை நிறுவனர்"],["முகமது ஷாஃபிக்","இணை நிறுவனர்"]]}},
    {h:"சதி வழக்குகள் (1922-1929)",body:"1921 ஜூன் 3இல் முதல் புரட்சிகர தேசியவாதக் குழுவினர் பெஷாவருக்கு வந்தனர். 1922-1927ஆம் ஆண்டுகளுக்கு இடையில் ஐந்து சதி வழக்குகள் தொடுக்கப்பட்டன.",
     tbl:{hs:["வழக்கு","ஆண்டு","இடம்"],rows:[["பெஷாவர் சதி வழக்கு (முதலாவது)","1921","பெஷாவர்"],["கான்பூர் (போல்ஷ்விக்) சதி வழக்கு","1924","கான்பூர்"],["மீரட் சதி வழக்கு","1929","மீரட்"],["இந்திய கம்யூனிஸ்ட் கட்சி (இந்தியாவில்)","1925","பம்பாய்"]]}}
  ]},
  {title:"5.1 கான்பூர் சதி வழக்கு, 1924",color:"#E63946",sections:[
    {h:"குற்றம் சாட்டப்பட்ட 13 பேர்",body:"கான்பூர் சதிவழக்கில் ஆரம்பத்தில் 13 பேர் மீது குற்றம் சுமத்தப்பட்டது.",
     tbl:{hs:["வ.எண்","பெயர்","குறிப்பு"],rows:[["1","எம்.என்.ராய்","ஜெர்மனியில் இருந்தார்"],["2","முசாபர் அகமது","4 ஆண்டுகள் கடுங்காவல்"],["3","சவுகத் உஸ்மானி","4 ஆண்டுகள் கடுங்காவல்"],["4","குலாம் ஹுசைன்","அரசுத் தரப்புச் சாட்சியாக மாறி விடுவிக்கப்பட்டார்"],["5","எஸ்.ஏ. டாங்கே","4 ஆண்டுகள் கடுங்காவல்"],["6","எம். சிங்காரவேலர்","உடல்நிலை காரணமாகப் பிணையில் விடுவிக்கப்பட்டார்"],["7","ஆர்.எல்.சர்மா","பாண்டிச்சேரியில் இருந்தார்"],["8","நளினி குப்தா","4 ஆண்டுகள் கடுங்காவல்"],["9","ஷமுத்தின் ஹாசன்","குற்றப்பத்திரிகை"],["10","எம். ஆர். எஸ். வேலாயுதன்","குற்றப்பத்திரிகை"],["11","டாக்டர் மணிலால்","குற்றப்பத்திரிகை"],["12","சம்பூர்ண நந்தா","குற்றப்பத்திரிகை"],["13","சத்ய பக்தா","குற்றப்பத்திரிகை"]]}},
    {h:"எம். சிங்காரவேலர் சிறப்பு குறிப்பு",body:"எம். சிங்காரவேலர் (18 பிப்ரவரி 1860 – 11 பிப்ரவரி 1946) மதராசில் பிறந்தார். இவர் இளமைக் காலத்தில் புத்தமதத்தைத் தழுவியவர்.",
     tbl:{hs:["சாதனை","விவரம்"],rows:[["மே தினம்","1923ஆம் ஆண்டு முதன்முறையாக நாட்டில் மே தினம் கொண்டாடினார்"],["தொழிற்சங்கம்","திரு. வி. கல்யாணசுந்தரத்துடன் இணைந்து தென்னிந்தியாவில் பல தொழிற்சங்கங்கள் தோற்றுவித்தார்"],["வேலைநிறுத்தம்","1928ஆம் ஆண்டு தென்னிந்திய ரயில்வே வேலைநிறுத்தம் (பொன்மலை, திருச்சிராப்பள்ளி) ஏற்பாடு செய்தார்"]]}}
  ]},
  {title:"5.2 மீரட் சதி வழக்கு, 1929",color:"#2A9D8F",sections:[
    {h:"முக்கிய வேலைநிறுத்தங்கள் (1927-1929)",body:"1929ஆம் ஆண்டின் மீரட் சதி வழக்குதான் ஆங்கிலேய அரசினரால் தொடுக்கப்பட்ட அனைத்துக் கம்யூனிஸ்ட் சதி வழக்குகளிலும் பெரிதும் புகழ்பெற்றதாகும்.",
     tbl:{hs:["வேலைநிறுத்தம்","ஆண்டு","இடம்"],rows:[["காரக்பூர் ரயில்வே பணிமனை","1927","காரக்பூர்"],["லில்லுவா ரயில் பணிமனை","1928","லில்லுவா"],["கல்கத்தா துப்புரவுத் தொழிலாளர்கள்","1928","கல்கத்தா"],["வங்காளத்தின் சணல் ஆலைகள்","1929","வங்காளம்"],["தென்னிந்திய ரயில்வே","1928","பொன்மலை, திருச்சி"],["பம்பாய் ஜவுளித் தொழிலாளர்","1928","பம்பாய்"]]}},
    {h:"விசாரணையும் தண்டனையும்",body:"கே.எஃப். நாரிமன், எம்.சி. சக்லா போன்ற புகழ்பெற்ற வழக்கறிஞர்கள் குற்றம் சாட்டப்பட்டவர்கள் சார்பில் வாதாடினர். காந்தியடிகள், ஜவகர்லால் நேரு போன்ற தேசியத் தலைவர்கள் சிறைக்கு வந்து குற்றம் சாட்டப்பட்டவர்களைப் பார்த்தனர். 1933 ஜனவரி 16இல் 27 பேர் தண்டிக்கப்பட்டனர். ரோமன் ரோலண்ட், ஆல்பர்ட் ஐன்ஸ்டீன் ஆதரவாக குரல் கொடுத்தனர். ஜூலை 1933இல் தண்டனை குறைக்கப்பட்டது.",tbl:null}
  ]},
  {title:"5.3 பகத்சிங்கும் கல்பனா தத்தும்",color:"#E9C46A",sections:[
    {h:"பகத்சிங்கின் முக்கிய தகவல்கள்",body:"பகத்சிங் தேசியவாதத்தின் ஓர் ஒப்பற்ற நிலையைப் பிரதிநிதித்துவப்படுத்துகிறார்.",
     tbl:{hs:["தகவல்","விவரம்"],rows:[["பிறப்பு","1907 செப்டம்பர் 28"],["பிறப்பிடம்","ஜார்ன்வாலா, லயல்பூர் மாவட்டம், பஞ்சாப் (இப்போது பாகிஸ்தான்)"],["தந்தை","கிஷன்சிங் (தாராளவாதி)"],["தாயார்","வித்யாவதி கவுர்"],["HSRA பெயர் மாற்றம்","1928இல் ஹிந்துஸ்தான் சோசலிஸ்ட் ரிபப்ளிகன் அசோசியேஷன்"],["குண்டு வீச்சு","1929 ஏப்ரல் 8 - மத்திய சட்டமன்றம்"],["மரண தண்டனை","1930 அக்டோபர் 7"],["தூக்கிலிடப்பட்டது","1931 மார்ச் 23 - லாகூர் சிறைச்சாலை"]]}},
    {h:"கல்பனா தத் (1913-1995)",body:"1920களின் பிற்பகுதியில் கல்பனா தத் என்னும் ஓர் இளம்பெண் சிட்டகாங் ஆயுதப் படைத்தளத்தை துணிகரமாகத் தாக்கியதன் மூலம் தேசபக்தியைக் கனன்றெழச் செய்தவர். கம்யூனிஸ்ட் தலைவர் பி.சி. ஜோஷியைத் திருமணம் செய்து கொண்ட பின்னர் கல்பனா ஜோஷி என்று அறியப்பட்டவர்.",
     tbl:{hs:["நிகழ்வு","தேதி / விவரம்"],rows:[["சிட்டகாங் தாக்குதல்","1930 ஏப்ரல் 18 இரவு"],["சூரியா சென் கைது","பிப்ரவரி 1933"],["சூரியா சென் தூக்குத்தண்டனை","1934 ஜனவரி 12"],["கல்பனா தத் தண்டனை","வாழ்நாள் நாடுகடத்தல்"],["குற்றச்சாட்டு","பேரரசருக்கு எதிரான போரை நடத்தியது"]]}}
  ]},
  {title:"5.4 கராச்சி அமர்வு, 1931",color:"#457B9D",sections:[
    {h:"கராச்சி அமர்வின் முக்கியத்துவம்",body:"மார்ச் 1931இல் நடந்த கராச்சி அமர்வு சர்தார் வல்லபாய் படேல் தலைமையில் அடிப்படை உரிமைகள் மற்றும் கடமைகளில் ஒரு தீர்மானத்தை நிறைவேற்றியது. அரசியல் சுதந்திரம் மற்றும் பொருளாதாரச் சுதந்திரம் என்பது பிரிக்கமுடியாத ஒன்றென்று உறுதிசெய்தன.",
     tbl:{hs:["அம்சம்","விவரம்"],rows:[["தேதி","மார்ச் 1931"],["தலைவர்","சர்தார் வல்லபாய் படேல்"],["முக்கிய தீர்மானம்","அடிப்படை உரிமைகள் மற்றும் கடமைகள்"],["அரசமைப்பில்","பகுதி III (அடிப்படை உரிமைகள்)"],["வழிகாட்டு நெறிமுறைகள்","பகுதி IV"],["காந்தியின் கொள்கைகள் + நேருவின் சோசலிச பார்வைகள்","இடம் பெற்றன"]]}}
  ]},
  {title:"5.5 உலகப் பெருமந்தமும் இந்தியாவிலும்",color:"#6D6875",sections:[
    {h:"பெருமந்தத்தின் தாக்கம்",body:"உலகப் பெருமந்த நிலை 1929இல் இருந்து ஒரு பத்தாண்டாக நீடித்த கடுமையான பொருளாதார நெருக்கடி ஆகும். வட அமெரிக்காவில் தொடங்கியது.",
     tbl:{hs:["தகவல்","விவரம்"],rows:[["காலம்","1929 - 1939 (10 ஆண்டுகள்)"],["தொடக்கம்","வட அமெரிக்கா - வால் தெரு வீழ்ச்சி"],["இந்திய ஏற்றுமதி 1929-30","ரூ.311 கோடி"],["இந்திய ஏற்றுமதி 1932-33","ரூ.132 கோடி"],["பருத்தி நுகர்வு 1929-30","44% வெளியிலிருந்து"],["பருத்தி நுகர்வு 1933-34","20.5% வெளியிலிருந்து"]]}}
  ]},
  {title:"5.6 இந்தியாவில் தொழில்துறை வளர்ச்சி",color:"#E76F51",sections:[
    {h:"முக்கிய தொழிற்சாலைகள் - காலவரிசை",body:"பிரிட்டிஷ் வணிகக் கொள்கையானது உள்நாட்டுத் தொழில்துறையைப் பெரும் எண்ணிக்கையாக்கியது. இந்தியாவைத் தொழில்மயமாக்குதல் பிரிட்டிஷ் கொள்கையின் ஒரு பகுதி அல்ல.",
     tbl:{hs:["ஆண்டு","நிகழ்வு"],rows:[["1843","பெங்கால் நிலக்கரி நிறுவனம் - துவாரகநாத் தாகூர்"],["1853 ஏப்ரல் 16","முதல் பயணிகள் ரயில் - பம்பாய் - தானே (34 கி.மீ)"],["1854","முதல் பருத்தி ஆலை - கவஸ்ஜீ நானாபாய் தவர், பம்பாய்"],["1855","முதல் சணல் ஆலை - கல்கத்தா"],["1860","முதல் தோல் ஆலை (அரசு) - கான்பூர்"],["1868","டாடா குழுமம் நிறுவப்பட்டது"],["1882","கூப்பர் பேப்பர் மில் - லக்னோ"],["1896","ஸ்டேன்ஸ் மில் - கோயம்புத்தூர்"],["1904","சிமெண்ட் உற்பத்தி - மதராஸ்"],["1905","முதல் இந்திய தோல் ஆலை - கல்கத்தா"],["1907","TISCO - சாகி நகர், பீகார் (தோரப்ஜி டாடா)"],["1910","டாடா நீர்மின்சக்தி நிறுவனம்"],["1914","பம்பாயில் 129 பருத்தி ஆலைகள்; கல்கத்தாவில் 64 சணல் ஆலைகள்"],["1919","சிந்தியா நீராவிக் கப்பல் கம்பெனி"],["1932","மதுக்கரை சிமெண்ட் தொழிற்சாலை - கோயம்புத்தூர்"]]}},
    {h:"TISCO உற்பத்தி வளர்ச்சி",body:"",
     tbl:{hs:["ஆண்டு","உற்பத்தி (டன்)"],rows:[["1912-13","31,000"],["1917-18","1,81,000"]]}},
    {h:"பருத்தி ஜவுளி ஆலைகள் வளர்ச்சி",body:"",
     tbl:{hs:["காலம்","ஆலைகள் எண்ணிக்கை"],rows:[["1875-76","47"],["1913-14","271"]]}}
  ]}
];

const css=`
@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+Tamil:wght@400;600;700&display=swap');
*{box-sizing:border-box;margin:0;padding:0;}
:root{--bg:#0D0D1A;--surface:#161628;--surface2:#1E1E3A;--accent:#FF6B35;--accent2:#E63946;--accent3:#2A9D8F;--gold:#E9C46A;--text:#F0F0F0;--text2:#9090B0;--border:#252545;--ok:#22c55e;--bad:#ef4444;}
body{background:var(--bg);color:var(--text);font-family:'Noto Sans Tamil',sans-serif;min-height:100vh;}
.app{max-width:1100px;margin:0 auto;padding:0 12px 40px;}
nav{display:flex;gap:4px;background:var(--surface);border-radius:16px;padding:6px;margin:10px 0;border:1px solid var(--border);}
nav button{flex:1;padding:10px 4px;border:none;border-radius:12px;background:transparent;color:var(--text2);cursor:pointer;font-family:inherit;font-size:13px;font-weight:700;transition:all .2s;}
nav button.active{background:var(--accent);color:#fff;box-shadow:0 0 20px rgba(255,107,53,.4);}
.note-card{background:var(--surface);border-radius:16px;overflow:hidden;border:1px solid var(--border);margin-bottom:12px;}
.note-head{padding:14px 16px;cursor:pointer;display:flex;justify-content:space-between;align-items:center;font-weight:700;font-size:15px;}
.note-body{padding:0 16px 16px;}
.sec{margin-top:12px;}
.sec h3{font-size:12px;font-weight:700;color:var(--accent);margin-bottom:6px;text-transform:uppercase;letter-spacing:.5px;}
.sec p{font-size:13px;line-height:1.7;color:var(--text2);}
table{width:100%;border-collapse:collapse;margin-top:8px;font-size:12px;}
th{background:var(--surface2);color:var(--accent);padding:8px 10px;text-align:left;border:1px solid var(--border);}
td{padding:7px 10px;border:1px solid var(--border);color:var(--text2);}
tr:hover td{background:rgba(255,107,53,.05);}
.qcard{background:var(--surface);border-radius:16px;padding:18px;border:1px solid var(--border);margin-bottom:12px;}
.qcard .sec-label{font-size:12px;color:var(--text2);margin-bottom:10px;}
.qcard .qtext{font-size:15px;font-weight:700;line-height:1.6;margin-bottom:14px;}
.opts{display:grid;grid-template-columns:1fr 1fr;gap:8px;}
@media(max-width:500px){.opts{grid-template-columns:1fr;}}
.opt{padding:11px;border:2px solid var(--border);border-radius:12px;background:var(--surface2);color:var(--text);cursor:pointer;font-family:inherit;font-size:13px;text-align:left;transition:all .2s;line-height:1.4;}
.opt:hover:not(:disabled){border-color:var(--accent);background:rgba(255,107,53,.1);}
.opt.ok{border-color:var(--ok);background:rgba(34,197,94,.15);color:var(--ok);}
.opt.bad{border-color:var(--bad);background:rgba(239,68,68,.15);color:var(--bad);}
.exp{background:rgba(42,157,143,.1);border-left:3px solid var(--accent3);padding:12px;border-radius:8px;margin-top:10px;font-size:13px;line-height:1.6;color:var(--text2);}
.btn{padding:10px 18px;border:none;border-radius:10px;cursor:pointer;font-family:inherit;font-weight:700;font-size:13px;transition:all .2s;}
.btn-p{background:var(--accent);color:#fff;}
.btn-s{background:var(--surface2);color:var(--text);border:1px solid var(--border);}
.pbar{background:var(--border);border-radius:4px;height:5px;margin-bottom:12px;overflow:hidden;}
.pfill{height:100%;background:var(--accent);border-radius:4px;transition:width .3s;}
.badge{display:inline-flex;align-items:center;gap:4px;padding:4px 10px;border-radius:20px;font-size:11px;font-weight:700;}
.bg{background:rgba(34,197,94,.2);color:var(--ok);}
.br{background:rgba(239,68,68,.2);color:var(--bad);}
.by{background:rgba(233,196,106,.2);color:var(--gold);}
.sboard{text-align:center;padding:32px;background:var(--surface);border-radius:20px;border:1px solid var(--border);}
.snum{font-size:56px;font-weight:700;color:var(--accent);}
.sfilt{display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px;}
.sfilt button{padding:6px 12px;border-radius:20px;border:1px solid var(--border);background:var(--surface);color:var(--text2);cursor:pointer;font-size:12px;font-family:inherit;}
.sfilt button.active{background:var(--accent);border-color:var(--accent);color:#fff;}
.inp{padding:8px 12px;border-radius:10px;border:1px solid var(--border);background:var(--surface2);color:var(--text);font-family:inherit;font-size:13px;}
.timer-ring{width:90px;height:90px;position:relative;margin:0 auto 16px;}
.timer-ring svg{transform:rotate(-90deg);}
.timer-txt{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);font-size:22px;font-weight:700;}
.gstat{display:flex;justify-content:center;gap:20px;margin-bottom:16px;flex-wrap:wrap;}
.si{text-align:center;}
.sn{font-size:24px;font-weight:700;color:var(--accent);}
.sl{font-size:11px;color:var(--text2);}
.gq{font-size:17px;font-weight:700;line-height:1.6;margin-bottom:18px;}
.gopts{display:grid;grid-template-columns:1fr 1fr;gap:10px;max-width:600px;margin:0 auto;}
@media(max-width:500px){.gopts{grid-template-columns:1fr;}}
.gopt{padding:14px;border:2px solid var(--border);border-radius:14px;background:var(--surface);color:var(--text);cursor:pointer;font-family:inherit;font-size:14px;font-weight:700;transition:all .2s;}
.gopt:hover:not(:disabled){border-color:var(--accent);transform:translateY(-2px);}
.gopt.ok{border-color:var(--ok);background:rgba(34,197,94,.2);}
.gopt.bad{border-color:var(--bad);background:rgba(239,68,68,.2);}
.rg{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:16px 0;}
.ri{background:var(--surface);border-radius:12px;padding:14px;border:1px solid var(--border);text-align:center;}
.rn{font-size:28px;font-weight:700;color:var(--accent);}
.rl{font-size:11px;color:var(--text2);margin-top:4px;}
`;

export default function Chapter5(){
  const[tab,setTab]=useState("notes");
  return(
    <>
      <style>{css}</style>
      <div className="app">
        <div style={{textAlign:"center",padding:"18px 0 8px"}}>
          <div style={{fontSize:11,color:"var(--text2)",letterSpacing:2,textTransform:"uppercase",marginBottom:4}}>வகுப்பு 12 · வரலாறு · அலகு 5</div>
          <h1 style={{fontSize:"clamp(15px,3.5vw,22px)",fontWeight:700,background:"linear-gradient(135deg,#FF6B35,#E63946)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",lineHeight:1.3}}>ஏகாதிபத்தியத்திற்கு எதிரான போராட்டங்களில்<br/>புரட்சிகர தேசியவாதத்தின் காலம்</h1>
        </div>
        <nav>
          {[{id:"notes",l:"📖 குறிப்புகள்"},{id:"quiz",l:"📝 வினாடி வினா"},{id:"game",l:"🎮 விளையாட்டு"}].map(t=>(
            <button key={t.id} className={tab===t.id?"active":""} onClick={()=>setTab(t.id)}>{t.l}</button>
          ))}
        </nav>
        {tab==="notes"&&<NotesTab/>}
        {tab==="quiz"&&<QuizTab/>}
        {tab==="game"&&<GameTab/>}
      </div>
    </>
  );
}

function NotesTab(){
  const[open,setOpen]=useState({});
  return(
    <div>
      {notesData.map((card,i)=>(
        <div key={i} className="note-card">
          <div className="note-head" style={{borderLeft:`4px solid ${card.color}`}} onClick={()=>setOpen(p=>({...p,[i]:!p[i]}))}>
            <span>{card.title}</span>
            <span style={{fontSize:18,color:card.color}}>{open[i]?"▲":"▼"}</span>
          </div>
          {open[i]&&(
            <div className="note-body">
              {card.sections.map((sec,j)=>(
                <div key={j} className="sec">
                  <h3>{sec.h}</h3>
                  {sec.body&&<p>{sec.body}</p>}
                  {sec.tbl&&(
                    <div style={{overflowX:"auto"}}>
                      <table>
                        <thead><tr>{sec.tbl.hs.map((h,k)=><th key={k}>{h}</th>)}</tr></thead>
                        <tbody>{sec.tbl.rows.map((row,k)=><tr key={k}>{row.map((cell,l)=><td key={l}>{cell}</td>)}</tr>)}</tbody>
                      </table>
                    </div>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

function QuizTab(){
  const sections=["அனைத்தும்",...Array.from(new Set(allQuestions.map(q=>q.s)))];
  const[filter,setFilter]=useState("அனைத்தும்");
  const[search,setSearch]=useState("");
  const[idx,setIdx]=useState(0);
  const[selected,setSelected]=useState(null);
  const[score,setScore]=useState({c:0,w:0});
  const[finished,setFinished]=useState(false);

  const filtered=allQuestions.filter(q=>{
    const sm=filter==="அனைத்தும்"||q.s===filter;
    const se=!search||q.q.includes(search)||q.o.some(o=>o.includes(search));
    return sm&&se;
  });
  const q=filtered[idx];

  const pick=(i)=>{
    if(selected!==null)return;
    setSelected(i);
    setScore(s=>({c:s.c+(i===q.a?1:0),w:s.w+(i!==q.a?1:0)}));
  };
  const next=()=>{
    if(idx<filtered.length-1){setIdx(idx+1);setSelected(null);}
    else setFinished(true);
  };
  const prev=()=>{if(idx>0){setIdx(idx-1);setSelected(null);}};
  const reset=()=>{setIdx(0);setSelected(null);setScore({c:0,w:0});setFinished(false);};

  if(finished)return(
    <div className="sboard">
      <div style={{fontSize:48}}>🎉</div>
      <div className="snum">{score.c}/{score.c+score.w}</div>
      <p style={{color:"var(--text2)",margin:"8px 0 16px"}}>நீங்கள் {Math.round(score.c/(score.c+score.w)*100)}% சரியாக பதிலளித்தீர்கள்!</p>
      <div style={{display:"flex",gap:10,justifyContent:"center",flexWrap:"wrap",marginBottom:16}}>
        <span className="badge bg">✓ சரி: {score.c}</span>
        <span className="badge br">✗ தவறு: {score.w}</span>
      </div>
      <button className="btn btn-p" onClick={reset}>மீண்டும் முயற்சி</button>
    </div>
  );

  return(
    <div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12,alignItems:"center"}}>
        <input className="inp" placeholder="தேடுக..." value={search} onChange={e=>{setSearch(e.target.value);setIdx(0);setSelected(null);}} style={{maxWidth:200}}/>
        <span className="badge by">📋 {filtered.length} வினாக்கள்</span>
        <span className="badge bg">✓ {score.c}</span>
        <span className="badge br">✗ {score.w}</span>
      </div>
      <div className="sfilt">
        {sections.map(s=>(
          <button key={s} className={filter===s?"active":""} onClick={()=>{setFilter(s);setIdx(0);setSelected(null);}}>{s}</button>
        ))}
      </div>
      {filtered.length===0?<p style={{color:"var(--text2)",textAlign:"center",padding:40}}>வினாக்கள் இல்லை</p>:(
        <>
          <div className="pbar"><div className="pfill" style={{width:`${(idx+1)/filtered.length*100}%`}}/></div>
          <div style={{textAlign:"right",fontSize:12,color:"var(--text2)",marginBottom:10}}>{idx+1} / {filtered.length}</div>
          {q&&(
            <div className="qcard">
              <div className="sec-label">📚 {q.s}</div>
              <div className="qtext">{q.q}</div>
              <div className="opts">
                {q.o.map((opt,i)=>{
                  let cls="opt";
                  if(selected!==null){if(i===q.a)cls+=" ok";else if(i===selected&&selected!==q.a)cls+=" bad";}
                  return<button key={i} className={cls} disabled={selected!==null} onClick={()=>pick(i)}>{String.fromCharCode(65+i)}. {opt}</button>;
                })}
              </div>
              {selected!==null&&<div className="exp">💡 {q.e}</div>}
              <div style={{display:"flex",gap:8,marginTop:12,flexWrap:"wrap"}}>
                <button className="btn btn-s" onClick={prev} disabled={idx===0}>← முந்தைய</button>
                <button className="btn btn-p" onClick={next}>{idx===filtered.length-1?"முடி":"அடுத்த →"}</button>
              </div>
            </div>
          )}
        </>
      )}
    </div>
  );
}

function GameTab(){
  const[phase,setPhase]=useState("start");
  const[qList,setQList]=useState([]);
  const[qi,setQi]=useState(0);
  const[tl,setTl]=useState(20);
  const[selected,setSelected]=useState(null);
  const[pts,setPts]=useState(0);
  const[streak,setStreak]=useState(0);
  const[maxStreak,setMaxStreak]=useState(0);
  const[wrong,setWrong]=useState(0);
  const[answers,setAnswers]=useState([]);
  const tRef=useRef(null);

  const shuffle=a=>[...a].sort(()=>Math.random()-.5);

  const startGame=(n=20)=>{
    const qs=shuffle(allQuestions).slice(0,n);
    setQList(qs);setQi(0);setPts(0);setStreak(0);setMaxStreak(0);setWrong(0);setAnswers([]);setTl(20);setSelected(null);setPhase("playing");
  };

  useEffect(()=>{
    if(phase!=="playing"||selected!==null)return;
    tRef.current=setInterval(()=>{
      setTl(t=>{
        if(t<=1){clearInterval(tRef.current);timeout();return 0;}
        return t-1;
      });
    },1000);
    return()=>clearInterval(tRef.current);
  },[phase,qi,selected]);

  const timeout=useCallback(()=>{
    const q=allQuestions[0];
    setSelected(-1);setStreak(0);setWrong(w=>w+1);
    setTimeout(()=>advance(),800);
  },[qi,qList]);

  const pick=(i)=>{
    clearInterval(tRef.current);
    if(selected!==null)return;
    const q=qList[qi];
    const ok=i===q.a;
    setSelected(i);
    const p=ok?10+Math.floor(tl/2):0;
    if(ok){setPts(s=>s+p);setStreak(s=>{const ns=s+1;setMaxStreak(m=>Math.max(m,ns));return ns;});}
    else{setStreak(0);setWrong(w=>w+1);}
    setAnswers(a=>[...a,{q:q.q,ca:q.a,ch:i,ok,p,opts:q.o}]);
    setTimeout(()=>advance(),1100);
  };

  const advance=()=>{
    setQi(i=>{
      const n=i+1;
      if(n>=qList.length){setPhase("result");return i;}
      setSelected(null);setTl(20);return n;
    });
  };

  const pct=qList.length?Math.round(answers.filter(a=>a.ok).length/qList.length*100):0;

  if(phase==="start")return(
    <div style={{textAlign:"center",padding:"40px 16px"}}>
      <div style={{fontSize:56,marginBottom:14}}>🎮</div>
      <h2 style={{fontSize:22,marginBottom:8}}>வினாடி வினா விளையாட்டு</h2>
      <p style={{color:"var(--text2)",marginBottom:24,lineHeight:1.6}}>ஒவ்வொரு வினாவிற்கும் 20 வினாடிகள் மட்டுமே!<br/>சரியான விடைக்கு 10+ புள்ளிகள்.</p>
      <div style={{display:"flex",gap:12,justifyContent:"center",flexWrap:"wrap"}}>
        {[10,20,30,50].map(n=><button key={n} className="btn btn-p" onClick={()=>startGame(n)}>🎯 {n} வினாக்கள்</button>)}
      </div>
    </div>
  );

  if(phase==="result")return(
    <div style={{padding:16}}>
      <div style={{textAlign:"center",marginBottom:20}}>
        <div style={{fontSize:56}}>{pct>=80?"🏆":pct>=60?"🥈":"🥉"}</div>
        <h2 style={{fontSize:22,marginBottom:4}}>{pct>=80?"சிறப்பான முடிவு!":pct>=60?"நல்ல முடிவு!":"மேலும் படிக்கவும்!"}</h2>
        <div className="rg">
          <div className="ri"><div className="rn">{pts}</div><div className="rl">மொத்த புள்ளிகள்</div></div>
          <div className="ri"><div className="rn" style={{color:"var(--ok)"}}>{answers.filter(a=>a.ok).length}</div><div className="rl">சரியான விடைகள்</div></div>
          <div className="ri"><div className="rn" style={{color:"var(--bad)"}}>{wrong}</div><div className="rl">தவறான விடைகள்</div></div>
          <div className="ri"><div className="rn" style={{color:"var(--gold)"}}>{pct}%</div><div className="rl">சதவீதம்</div></div>
          <div className="ri"><div className="rn" style={{color:"#a78bfa"}}>{maxStreak}</div><div className="rl">அதிகபட்ச தொடர்ச்சி</div></div>
          <div className="ri"><div className="rn" style={{color:"var(--accent3)"}}>{qList.length}</div><div className="rl">மொத்த வினாக்கள்</div></div>
        </div>
        <button className="btn btn-p" onClick={()=>setPhase("start")}>மீண்டும் விளையாடு</button>
      </div>
      <h3 style={{marginBottom:10}}>விடைகளின் விவரம்:</h3>
      <div style={{maxHeight:350,overflowY:"auto"}}>
        {answers.map((a,i)=>(
          <div key={i} style={{background:"var(--surface)",borderRadius:10,padding:"10px 12px",marginBottom:8,borderLeft:`4px solid ${a.ok?"var(--ok)":"var(--bad)"}`}}>
            <p style={{fontSize:13,marginBottom:4}}>{i+1}. {a.q}</p>
            <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
              <span className={`badge ${a.ok?"bg":"br"}`}>{a.ok?"✓ சரி":"✗ தவறு"}</span>
              {!a.ok&&<span style={{fontSize:12,color:"var(--text2)"}}>சரியான விடை: {a.opts[a.ca]}</span>}
              {a.ok&&<span style={{fontSize:12,color:"var(--gold)"}}>+{a.p} புள்ளிகள்</span>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const q=qList[qi];
  if(!q)return null;
  const R=38,C=2*Math.PI*R;
  const doff=C*(1-tl/20);

  return(
    <div style={{textAlign:"center",padding:16}}>
      <div className="gstat">
        <div className="si"><div className="sn">{pts}</div><div className="sl">புள்ளிகள்</div></div>
        <div className="si"><div className="sn" style={{color:"var(--ok)"}}>{answers.filter(a=>a.ok).length}</div><div className="sl">சரி</div></div>
        <div className="si"><div className="sn" style={{color:"var(--bad)"}}>{wrong}</div><div className="sl">தவறு</div></div>
        <div className="si"><div className="sn" style={{color:"var(--gold)"}}>{qi+1}/{qList.length}</div><div className="sl">வினா</div></div>
      </div>
      {streak>1&&<div style={{color:"var(--gold)",fontWeight:700,marginBottom:8}}>🔥 {streak} தொடர்ச்சி!</div>}
      <div className="timer-ring">
        <svg width="90" height="90" viewBox="0 0 90 90">
          <circle cx="45" cy="45" r={R} fill="none" stroke="var(--border)" strokeWidth="7"/>
          <circle cx="45" cy="45" r={R} fill="none"
            stroke={tl>10?"var(--accent3)":tl>5?"var(--gold)":"var(--bad)"}
            strokeWidth="7" strokeLinecap="round"
            strokeDasharray={C} strokeDashoffset={doff}
            style={{transition:"stroke-dashoffset 1s linear"}}/>
        </svg>
        <div className="timer-txt" style={{color:tl>10?"var(--text)":tl>5?"var(--gold)":"var(--bad)"}}>{tl}</div>
      </div>
      <div className="gq">{q.q}</div>
      <div className="gopts">
        {q.o.map((opt,i)=>{
          let cls="gopt";
          if(selected!==null){if(i===q.a)cls+=" ok";else if(i===selected&&selected!==q.a)cls+=" bad";}
          return<button key={i} className={cls} disabled={selected!==null} onClick={()=>pick(i)}>{String.fromCharCode(65+i)}. {opt}</button>;
        })}
      </div>
    </div>
  );
}
